sql:
SELECT MAX(crime_rate) AS max_average_crime_rate
FROM neighborhoods
WHERE population > 20000 AND crime_rate > (SELECT AVG(crime_rate) FROM neighborhoods WHERE population > 20000);

SELECT COUNT(log_id) 
FROM incident_logs 
WHERE log_status = 'pending';

SELECT COUNT(*) 
FROM beats 
WHERE crime_rate > (SELECT AVG(crime_rate) FROM beats);

SELECT COUNT(analysis_id) 
FROM crime_analysis 
WHERE analysis_status = 'completed' AND analysis_type = 'trend';

external_knowledge:
- 'Guardians' refers to users who are associated with high-activity alerts;
- 'Waves of high activity' refers to the alert messages from the `alerts` table where the alert type is 'high activity';
- 'Caught the attention' means the alerts are linked to specific incident reports in the `incident_reports` table.

sql:
SELECT beat_name
FROM beats
WHERE crime_rate > (SELECT AVG(crime_rate) FROM beats);

SELECT beat_name, crime_rate 
FROM beats 
ORDER BY crime_rate DESC;

SELECT crime_name, severity_level
FROM crime_types
WHERE severity_level = (
  SELECT MAX(severity_level)
  FROM crime_types
);

SELECT beat_name, crime_rate
FROM beats
WHERE crime_rate > 0.005 AND area > 5;

external_knowledge:
- 'Beats' refer to specific patrol areas in law enforcement;
- 'Trend analysis' involves studying patterns and changes over time;
- 'NPU' stands for Neighborhood Planning Unit, a local government entity;
- 'Crime rate' is typically measured as the number of crimes per 1,000 people.

sql:
SELECT shift_name, officer_count
FROM shifts
ORDER BY officer_count DESC;

SELECT neighborhood_name, crime_rate 
FROM neighborhoods
WHERE crime_rate > (SELECT crime_rate FROM neighborhoods WHERE neighborhood_name = 'Downtown');

external_knowledge:
- "shadow of crime looms heavily" refers to a crime rate greater than 0.15;
- "rallied more than 10 units of resources" refers to the quantity of resources allocated being greater than 10;
- "guardians of the city" refers to the city's resource allocation system.

- A "beat" refers to a specific area patrolled by police officers;
- "Stormiest" is a metaphor for the highest crime rate;
- Crime rate is a measure of the number of crimes per unit of population or area.

sql:
SELECT beat_name
FROM beats
WHERE crime_rate = (SELECT MAX(crime_rate) FROM beats);

external_knowledge:
- "beats" refer to areas in the city where law enforcement or other services operate;
- "incident reports" are records of disturbances or issues reported in these areas;
- "population" refers to the number of people living in the beat area.

sql:
SELECT AVG(crime_rate) AS average_crime_rate
FROM beats
WHERE population > (SELECT AVG(population) FROM neighborhoods);

external_knowledge:
- "the beat of crime is the loudest" refers to the area with the highest crime rate;
- "the most troubled area" refers to the area with the highest number of reported incidents;
- "brave souls who patrol it" refers to the users assigned to that beat.

- "Darkest shadows" refers to neighborhoods with the highest crime rates;
- "Troubled areas" refers to neighborhoods with significant crime issues;
- "Average conclusion" is the mean value of the conclusions drawn from the crime analysis reports.

sql:
SELECT AVG(crime_rate) AS overall_average_crime_rate
FROM beats
WHERE beat_id IN (
  SELECT beat_id
  FROM resource_allocations
);
